import json
d=json.load(open("trajectories/7__cand_0007__t0.json"))
r=d["rollout"]
print("rollout keys:«redacted» list(r.keys()))
print("reward:", r.get("reward"))
for k in ("info","reward_info","scoring","evaluation","metrics"):
    if k in r: print(k, "=>", json.dumps(r[k])[:2500])
last=None
toolcalls=[]
for m in r["output"]:
    if m.get("role")=="assistant" and m.get("content"):
        last=m["content"]
    if m.get("tool_calls"):
        for t in m["tool_calls"]:
            toolcalls.append(t["name"]+" "+json.dumps(t["arguments"]))
print("=== TOOL CALLS ===")
for t in toolcalls: print(t)
print("=== LAST ASSISTANT ===")
print(last)
